{"code": "import ast

# Get the list of business_refs from 2018 reviews
refs_2018 = [row['business_ref'] for row in env['data_1']]
# Convert to business_id format
ids_2018 = set([f"businessid_{ref.split('_')[1]}" for ref in refs_2018])

# Filter mongo data
businesses = env['data_2']
count = 0

for b in businesses:
    if 'business_id' not in b or b['business_id'] not in ids_2018:
        continue

    attrs = b.get('attributes')
    if not attrs:
        continue

    has_parking = False

    # Check bike parking
    if attrs.get('BikeParking') == 'True':
        has_parking = True

    # Check business parking
    bp = attrs.get('BusinessParking')
    if bp and bp != 'None':
        try:
            bp_dict = ast.literal_eval(bp)
            if any(bp_dict.values()):
                has_parking = True
        except:
            pass

    if has_parking:
        count += 1

print(f"Count: {count}")
"}
